@layer base {
  :root {
    --radius: 0.625rem;

    /* ========================================
       Theme 1 — China Mobile Blue (Default)
       ======================================== */
    --bg-primary: #FFFFFF;
    --bg-secondary: #F8FAFC;
    --bg-accent: #E8F4FD;
    --primary: #0066CC;
    --primary-dark: #004C99;
    --secondary: #00B4D8;
    --accent: #FF6B35;
    --text-primary: #1E293B;
    --text-secondary: #64748B;
    --text-light: #94A3B8;
    --border: #E2E8F0;
    --success: #10B981;
    --card-bg: #FFFFFF;
    --shadow: rgba(0, 102, 204, 0.08);

    /* shadcn compatibility */
    --background: 0 0% 100%;
    --foreground: 222 47% 11%;
    --card: 0 0% 100%;
    --card-foreground: 222 47% 11%;
