    --card: 0 0% 100%;
    --card-foreground: 20 14% 14%;
    --popover: 40 50% 98%;
    --popover-foreground: 20 14% 14%;
    --primary-hsl: 210 100% 40%;
    --primary-foreground: 0 0% 100%;
    --secondary-hsl: 199 95% 49%;
    --secondary-foreground: 20 14% 14%;
    --muted: 30 40% 95%;
    --muted-foreground: 25 8% 45%;
    --accent-hsl: 17 100% 60%;
    --accent-foreground: 20 14% 14%;
    --destructive: 0 84% 60%;
    --destructive-foreground: 0 0% 98%;
    --input: 30 20% 90%;
    --ring: 210 100% 40%;
    --sidebar-background: 40 50% 98%;
    --sidebar-foreground: 20 14% 14%;
    --sidebar-primary: 210 100% 40%;
    --sidebar-primary-foreground: 0 0% 100%;
    --sidebar-accent: 30 40% 95%;
    --sidebar-accent-foreground: 20 14% 14%;
    --sidebar-border: 30 20% 90%;
    --sidebar-ring: 210 100% 40%;
  }

  html {
