          </h2>
          <p className="text-h3 text-[var(--text-secondary)] mb-6">
            理不清它们之间的关系？
          </p>
          <p className="text-body text-[var(--text-light)] animate-pulse">
            点击继续 →
          </p>
        </div>
      )}

      {/* Phase 2: Answer — 回归系统本身 */}
      {phase === 2 && (
        <div className="relative z-10 text-center max-w-3xl mx-auto">
          <h2 className="chaos-answer-title text-h1 font-bold text-[var(--text-primary)] mb-10 opacity-0">
            让我们回归系统本身
          </h2>
          <div className="flex items-center justify-center gap-4 md:gap-6 mt-6">
            {[
              { label: '输入', sub: '用户要什么', icon: MessageSquare, color: 'var(--primary)' },
              { label: '处理', sub: '系统怎么做', icon: Cpu, color: 'var(--accent)' },
              { label: '输出', sub: '结果是什么', icon: Eye, color: 'var(--success)' },
            ].map((item, i) => (
              <React.Fragment key={i}>
                {i > 0 && (
                  <span className="chaos-answer-flow text-2xl text-[var(--text-light)] opacity-0">→</span>
                )}
                <div className="chaos-answer-flow flex flex-col items-center px-5 py-4 md:px-8 md:py-5 rounded-xl border-2 opacity-0"
                  style={{ borderColor: item.color, backgroundColor: `${item.color}08` }}>
                  <item.icon size={28} style={{ color: item.color }} strokeWidth={1.8} />
                  <span className="text-h2 font-bold mt-2" style={{ color: item.color }}>{item.label}</span>
                  <span className="text-caption text-[var(--text-secondary)] mt-1">{item.sub}</span>
                </div>
              </React.Fragment>
            ))}
          </div>
          <p className="text-body text-[var(--text-light)] mt-10 animate-pulse">
            点击进入下一页 →
          </p>
        </div>
      )}

      {/* Bottom hint */}
      <div className="absolute bottom-8 text-caption text-[var(--text-light)]">
        {phase === 0 ? '点击任意处继续' : phase === 1 ? '点击任意处继续' : '点击重置'}
      </div>
    </section>
  );
};

export default memo(Slide01_Cover);

