import React, { useRef, memo, useState } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { ArrowRight, MousePointerClick } from 'lucide-react';

interface SlideProps { isActive: boolean; }

const GEAR_DEFS = [
  {
    label: '输入',
    icon: '📥',
    color: 'var(--primary)',
    desc: '用户对系统的操作和指令',
    detail: '使用操作成本 (Participation)',
    tag: 'P',
  },
  {
    label: '处理',
    icon: '⚙️',
    color: 'var(--accent)',
    desc: '系统内部的加工与运算',
    detail: '系统建设成本 (Complexity)',
    tag: 'C',
  },
  {
    label: '输出',
    icon: '📤',
    color: 'var(--success)',
    desc: '系统返回的结果与反馈',
    detail: '运营维护成本 (Uncertainty)',
    tag: 'U',
  },
];

const Slide02_Chaos: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [phase, setPhase] = useState(0); // 0=gears, 1=hover definitions, 2=cost labels, 3=triangle
  const [hoveredGear, setHoveredGear] = useState<number | null>(null);

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      gsap.fromTo('.tri-title', { opacity: 0, y: -20 }, { opacity: 1, y: 0, duration: 0.6 });
      gsap.fromTo('.tri-intro', { opacity: 0 }, { opacity: 1, duration: 0.5, delay: 0.3 });
      gsap.fromTo('.tri-gear', { opacity: 0, scale: 0.5, rotation: -180 },
        { opacity: 1, scale: 1, rotation: 0, duration: 0.7, stagger: 0.15, ease: 'back.out(1.7)', delay: 0.5 });
      gsap.fromTo('.tri-arrow', { opacity: 0, scaleX: 0 }, { opacity: 1, scaleX: 1, duration: 0.4, stagger: 0.15, delay: 1.0 });
      gsap.fromTo('.tri-hint', { opacity: 0 }, { opacity: 1, duration: 0.5, delay: 1.5 });
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive] });

  const handleClick = () => {
    if (phase === 0) {
      const ctx = gsap.context(() => {
        gsap.to('.tri-intro', { opacity: 0, y: -10, duration: 0.3 });
        gsap.to('.tri-hint', { opacity: 0, duration: 0.2 });
        gsap.fromTo('.tri-cost-section', { opacity: 0, y: 40 },
          { opacity: 1, y: 0, duration: 0.6, ease: 'power3.out', delay: 0.4 });
        gsap.fromTo('.tri-cost-card', { opacity: 0, scale: 0.8, y: 20 },
          { opacity: 1, scale: 1, y: 0, duration: 0.5, stagger: 0.12, ease: 'back.out(1.5)', delay: 0.6 });
        gsap.fromTo('.tri-cost-hint', { opacity: 0 }, { opacity: 1, duration: 0.5, delay: 1.2 });
      }, containerRef);
      ctx.revert();
      setPhase(1);
    } else if (phase === 1) {
      const ctx = gsap.context(() => {
        gsap.to('.tri-cost-hint', { opacity: 0, duration: 0.2 });
        gsap.to('.tri-cost-cards-row', { opacity: 0, y: -20, duration: 0.4 });
        gsap.fromTo('.tri-triangle-section', { opacity: 0, scale: 0.8 },
          { opacity: 1, scale: 1, duration: 0.7, ease: 'power3.out', delay: 0.4 });
        gsap.fromTo('.tri-triangle-edge', { strokeDashoffset: 200, opacity: 0 },
          { strokeDashoffset: 0, opacity: 1, duration: 0.8, stagger: 0.2, ease: 'power2.out', delay: 0.6 });
        gsap.fromTo('.tri-triangle-label', { opacity: 0, scale: 0 },
          { opacity: 1, scale: 1, duration: 0.5, stagger: 0.15, ease: 'back.out(2)', delay: 1.0 });
        gsap.fromTo('.tri-conclusion', { opacity: 0, y: 20 },
          { opacity: 1, y: 0, duration: 0.6, delay: 1.6 });
      }, containerRef);
      ctx.revert();
      setPhase(2);
    } else {
      setPhase(0);
    }
  };

  return (
    <section ref={containerRef}
      className="w-full min-h-[100dvh] flex flex-col items-center justify-center px-6 py-12 relative overflow-hidden cursor-pointer select-none"
      style={{ backgroundColor: 'var(--bg-primary)' }}
      onClick={handleClick}>

      {/* Title */}
      <h2 className="tri-title text-h1 font-bold text-[var(--text-primary)] mb-3 opacity-0">
        不可能三角
      </h2>
      <p className="tri-intro text-body text-[var(--text-secondary)] max-w-xl text-center mb-8 opacity-0">
        技术的发展是让人越来越自动化地去完成工作。<br />
        而构建一个自动化系统，核心就是三个模块：
      </p>

      {/* Three Gears / Chain Wheels */}
      <div className="flex items-center justify-center gap-3 md:gap-5 mb-4">
        {GEAR_DEFS.map((gear, i) => (
          <React.Fragment key={i}>
            <div
              className="tri-gear relative flex flex-col items-center px-5 py-4 md:px-7 md:py-5 rounded-xl border-2 transition-all duration-300 opacity-0"
              style={{
                borderColor: gear.color,
                backgroundColor: hoveredGear === i ? `${gear.color}15` : `${gear.color}08`,
                boxShadow: hoveredGear === i ? `0 0 20px ${gear.color}30` : 'none',
              }}
              onMouseEnter={() => setHoveredGear(i)}
              onMouseLeave={() => setHoveredGear(null)}>
              <span className="text-3xl md:text-4xl mb-2">{gear.icon}</span>
              <span className="text-h3 font-bold" style={{ color: gear.color }}>{gear.label}</span>
              <span className="text-caption text-[var(--text-secondary)] mt-1">{gear.desc}</span>
              {hoveredGear === i && (
                <div className="absolute -bottom-16 left-1/2 -translate-x-1/2 px-4 py-2 rounded-lg text-caption whitespace-nowrap z-20 shadow-lg"
                  style={{ backgroundColor: 'var(--card-bg)', border: `1px solid ${gear.color}` }}>
                  <span className="font-bold" style={{ color: gear.color }}>{gear.tag}</span>
                  {' '}{gear.detail}
                </div>
              )}
            </div>
            {i < 2 && (
              <ArrowRight className="tri-arrow w-6 h-6 text-[var(--text-light)] opacity-0" />
            )}
          </React.Fragment>
        ))}
      </div>

      <p className="tri-hint text-caption text-[var(--text-light)] flex items-center gap-1.5 mt-4 opacity-0">
        <MousePointerClick size={14} /> 悬停查看定义 · 点击继续
      </p>

      {/* Phase 1: Three Cost Labels */}
      {phase >= 1 && (
        <div className="tri-cost-section mt-8 opacity-0">
          <div className="tri-cost-cards-row flex items-start justify-center gap-4 md:gap-6">
            {[
              { tag: 'C', full: 'Complexity', zh: '复杂度', desc: '系统构建的开发成本', color: 'var(--accent)', value: '设计·编码·测试' },
              { tag: 'P', full: 'Participation', zh: '参与度', desc: '使用操作的人力成本', color: 'var(--primary)', value: '操作·决策·规划' },
              { tag: 'U', full: 'Uncertainty', zh: '不确定度', desc: '结果纠错的维护成本', color: 'var(--success)', value: '校验·调整·兜底' },
            ].map((cost, i) => (
              <div key={i}
                className="tri-cost-card flex flex-col items-center px-4 py-3 md:px-6 md:py-4 rounded-xl border-2 opacity-0"
                style={{ borderColor: cost.color, backgroundColor: `${cost.color}08` }}>
                <span className="text-h2 font-extrabold" style={{ color: cost.color }}>{cost.tag}</span>
                <span className="text-caption font-semibold text-[var(--text-primary)]">{cost.full}</span>
                <span className="text-body-sm text-[var(--text-secondary)] mt-1">{cost.zh}</span>
                <div className="w-full h-px my-2" style={{ backgroundColor: `${cost.color}30` }} />
                <span className="text-caption text-[var(--text-light)] text-center">{cost.desc}</span>
                <span className="text-caption text-[var(--text-light)] mt-1 text-center" style={{ color: cost.color }}>{cost.value}</span>
              </div>
            ))}
          </div>
          <p className="tri-cost-hint text-body text-[var(--text-secondary)] text-center mt-6 opacity-0">
            每个自动化系统都必须在这三个维度上分配成本 →
          </p>
        </div>
      )}

      {/* Phase 2: Impossible Triangle Visual */}
      {phase >= 2 && (
        <div className="tri-triangle-section flex flex-col items-center mt-6 opacity-0">
          <svg width="320" height="200" viewBox="0 0 320 200" className="mb-4">
            {/* Triangle edges */}
            <line className="tri-triangle-edge" x1="160" y1="20" x2="40" y2="170"
              stroke="var(--primary)" strokeWidth="2.5" strokeDasharray="200" opacity="0" />
            <line className="tri-triangle-edge" x1="40" y1="170" x2="280" y2="170"
              stroke="var(--accent)" strokeWidth="2.5" strokeDasharray="200" opacity="0" />
            <line className="tri-triangle-edge" x1="280" y1="170" x2="160" y2="20"
              stroke="var(--success)" strokeWidth="2.5" strokeDasharray="200" opacity="0" />

            {/* Vertex labels */}
            <g className="tri-triangle-label opacity-0">
              <circle cx="160" cy="20" r="22" fill="var(--primary)15" stroke="var(--primary)" strokeWidth="2" />
              <text x="160" y="25" textAnchor="middle" fill="var(--primary)" fontSize="14" fontWeight="bold">P</text>
              <text x="160" y="-2" textAnchor="middle" fill="var(--text-secondary)" fontSize="10">参与度</text>
            </g>
            <g className="tri-triangle-label opacity-0">
              <circle cx="40" cy="170" r="22" fill="var(--accent)15" stroke="var(--accent)" strokeWidth="2" />
              <text x="40" y="175" textAnchor="middle" fill="var(--accent)" fontSize="14" fontWeight="bold">C</text>
              <text x="40" y="198" textAnchor="middle" fill="var(--text-secondary)" fontSize="10">复杂度</text>
            </g>
            <g className="tri-triangle-label opacity-0">
              <circle cx="280" cy="170" r="22" fill="var(--success)15" stroke="var(--success)" strokeWidth="2" />
              <text x="280" y="175" textAnchor="middle" fill="var(--success)" fontSize="14" fontWeight="bold">U</text>
              <text x="280" y="198" textAnchor="middle" fill="var(--text-secondary)" fontSize="10">不确定度</text>
            </g>

            {/* Center text */}
            <text x="160" y="125" textAnchor="middle" fill="var(--text-primary)" fontSize="13" fontWeight="600" opacity="0.7">
              不可能三角
            </text>
            <text x="160" y="142" textAnchor="middle" fill="var(--text-light)" fontSize="10">
              三者不可同时最优
            </text>
          </svg>

          <div className="tri-conclusion text-center max-w-lg opacity-0">
            <p className="text-h3 font-bold text-[var(--text-primary)]">
              所有的技术选择，都是围绕这个三角进行的取舍
            </p>
            <p className="text-body text-[var(--text-secondary)] mt-2">
              你无法同时拥有「极简开发」「完全确定」「零成本使用」
            </p>
          </div>
        </div>
      )}

      {/* Bottom hint */}
      <div className="absolute bottom-6 text-caption text-[var(--text-light)]">
        {phase === 0 ? '悬停齿轮查看定义 · 点击继续' : phase === 1 ? '点击查看不可能三角' : '点击重置'}
      </div>
    </section>
  );
};

export default memo(Slide02_Chaos);

