import React, { useRef, memo, useState } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { Shield, Eye, Sparkles, Crown, Lock, ChevronRight } from 'lucide-react';

interface SlideProps { isActive: boolean; }

interface CharStats {
  C: number;
  P: number;
  U: number;
  special: string;
  specialDesc: string;
  pro: string;
  con: string;
}

interface Character {
  name: string;
  classType: string;
  mode: string;
  color: string;
  icon: React.ReactNode;
  stats: CharStats;
  imgPrompt: string;
}

const CHARACTERS: Character[] = [
  {
    name: '传统代码开发',
    classType: '【坚盾职业】执行者',
    mode: '执行',
    color: '#3B82F6',
    icon: <Shield size={24} />,
    stats: {
      C: 90, P: 15, U: 5,
      special: '绝对确定性',
      specialDesc: '逻辑完全可控，输出零偏差',
      pro: '结果100%可预测，边界清晰',
      con: '开发周期长，灵活性极低',
    },
    imgPrompt: 'A stoic medieval knight in full plate armor holding a massive tower shield, standing firm on a castle wall. Blue color theme. The shield has circuit board patterns etched into it. RPG character portrait style, dark fantasy, detailed digital art, clean background',
  },
  {
    name: '传统机器学习',
    classType: '【游侠职业】判断者',
    mode: '判断',
    color: '#10B981',
    icon: <Eye size={24} />,
    stats: {
      C: 60, P: 35, U: 30,
      special: '经验封装',
      specialDesc: '将大量分析经验固化为模型',
      pro: '可处理非结构化数据，有一定泛化能力',
      con: '需要大量标注数据，场景迁移成本高',
    },
    imgPrompt: 'A wise ranger archer with a glowing green eye, standing in a forest of data streams. The ranger holds a bow that fires arrows of light tracing prediction curves. Green color theme. RPG character portrait style, fantasy digital art, clean background',
  },
  {
    name: '普通大模型',
    classType: '【法师职业】规划者',
    mode: '规划',
    color: '#8B5CF6',
    icon: <Sparkles size={24} />,
    stats: {
      C: 10, P: 70, U: 80,
      special: '通用智能',
      specialDesc: '涌现出跨领域的推理规划能力',
      pro: '零门槛使用，覆盖面极广',
      con: '不确定性极高，结果不可控',
    },
    imgPrompt: 'A powerful wizard with swirling cosmic energy and nebula around their hands, purple arcane runes floating in the air. The wizard has an unpredictable, chaotic aura. Purple color theme. RPG character portrait style, fantasy digital art, clean background',
  },
];

const OPENCLAW: Character = {
  name: 'OpenClaw',
  classType: '【氪金隐藏角色】全能者',
  mode: '智能体',
  color: '#F59E0B',
  icon: <Crown size={24} />,
  stats: {
    C: 50, P: 8, U: 15,
    special: 'Skills + Memory',
    specialDesc: '渐进式加载 + 经验自动沉淀',
    pro: '最低参与度 + 可控不确定度，AI承担开发成本',
    con: '需要Token预算，前期需要投入养"虾"',
  },
  imgPrompt: 'An overpowered golden legendary RPG character, a regal figure wearing a crown and ornate golden armor with glowing orange runes. Multiple ethereal weapons and tools orbit around them. Golden aura with dollar signs subtly embedded. "Pay to Win" aesthetic but majestic. Orange and gold color theme. RPG character portrait style, epic fantasy digital art, clean background',
};

function StatBar({ label, value, max, color }: { label: string; value: number; max: number; color: string }) {
  const pct = (value / max) * 100;
  return (
    <div className="flex items-center gap-2 mb-1.5">
      <span className="text-caption font-bold w-5 text-right" style={{ color }}>{label}</span>
      <div className="flex-1 h-3 rounded-full overflow-hidden" style={{ backgroundColor: `${color}20` }}>
        <div className="h-full rounded-full transition-all duration-700"
          style={{ width: `${pct}%`, backgroundColor: color }} />
      </div>
      <span className="text-caption font-mono w-7 text-right" style={{ color }}>{value}</span>
    </div>
  );
}

function CharCard({ char, index, isHidden, onReveal }: {
  char: Character;
  index: number;
  isHidden?: boolean;
  onReveal?: () => void;
}) {
  const isPayToWin = char.name === 'OpenClaw';
  return (
    <div className={`game-card relative rounded-xl border-2 p-4 md:p-5 w-full transition-all duration-500 ${isPayToWin ? 'ring-2 ring-offset-2' : ''}`}
      style={{
        borderColor: char.color,
        backgroundColor: `${char.color}06`,
        boxShadow: isPayToWin ? `0 0 30px ${char.color}30` : `${char.color}10`,
      }}>
      {/* Header */}
      <div className="flex items-center gap-2 mb-3">
        <div className="w-9 h-9 rounded-lg flex items-center justify-center" style={{ backgroundColor: `${char.color}15`, color: char.color }}>
          {isHidden ? <Lock size={20} /> : char.icon}
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <span className="text-body font-bold text-[var(--text-primary)] truncate">{char.name}</span>
            {isPayToWin && <span className="text-caption px-1.5 py-0.5 rounded font-bold text-white" style={{ backgroundColor: char.color }}>氪金</span>}
          </div>
          <span className="text-caption" style={{ color: char.color }}>{char.classType}</span>
        </div>
      </div>

      {/* Image placeholder */}
      <div className="w-full h-24 md:h-28 rounded-lg mb-3 flex items-center justify-center border border-dashed overflow-hidden"
        style={{ borderColor: `${char.color}40`, backgroundColor: `${char.color}05` }}>
        {isHidden ? (
          <div className="text-center">
            <Lock size={28} className="mx-auto mb-1" style={{ color: `${char.color}50` }} />
            <span className="text-caption" style={{ color: `${char.color}70` }}>??? 未解锁</span>
          </div>
        ) : (
          <span className="text-caption text-center px-2 text-[var(--text-light)] italic">
            [图片占位]
          </span>
        )}
      </div>

      {/* Stats */}
      <div className="mb-3">
        <StatBar label="C" value={char.stats.C} max={100} color="var(--accent)" />
        <StatBar label="P" value={char.stats.P} max={100} color="var(--primary)" />
        <StatBar label="U" value={char.stats.U} max={100} color="var(--success)" />
      </div>

      {/* Special ability */}
      <div className="rounded-lg px-3 py-2 mb-2" style={{ backgroundColor: `${char.color}10` }}>
        <div className="flex items-center gap-1.5 mb-0.5">
          <Sparkles size={12} style={{ color: char.color }} />
          <span className="text-caption font-bold" style={{ color: char.color }}>{char.stats.special}</span>
        </div>
        <span className="text-caption text-[var(--text-secondary)]">{char.stats.specialDesc}</span>
      </div>

      {/* Pro / Con */}
      <div className="space-y-1 text-caption">
        <div className="flex gap-1.5">
          <span className="text-[var(--success)] shrink-0">+</span>
          <span className="text-[var(--text-secondary)]">{char.stats.pro}</span>
        </div>
        <div className="flex gap-1.5">
          <span className="text-[var(--accent)] shrink-0">−</span>
          <span className="text-[var(--text-secondary)]">{char.stats.con}</span>
        </div>
      </div>

      {/* Reveal button for hidden card */}
      {isHidden && onReveal && (
        <button onClick={(e) => { e.stopPropagation(); onReveal(); }}
          className="absolute inset-0 w-full h-full rounded-xl flex items-center justify-center bg-black/40 hover:bg-black/50 transition-colors cursor-pointer z-10">
          <div className="text-center text-white">
            <Lock size={32} className="mx-auto mb-2" />
            <span className="text-body font-bold">点击解锁隐藏角色</span>
          </div>
        </button>
      )}
    </div>
  );
}

const Slide03_Ecosystem: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [revealed, setRevealed] = useState(false);

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      gsap.fromTo('.game-title', { opacity: 0, y: -20 }, { opacity: 1, y: 0, duration: 0.6 });
      gsap.fromTo('.game-subtitle', { opacity: 0 }, { opacity: 1, duration: 0.5, delay: 0.3 });
      gsap.fromTo('.game-card', { opacity: 0, y: 30, scale: 0.95 },
        { opacity: 1, y: 0, scale: 1, duration: 0.5, stagger: 0.12, ease: 'back.out(1.5)', delay: 0.5 });
    }, containerRef);
