import React, { useRef, memo, useState } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { Sparkles, FileText, Search, Wrench, ClipboardList, ChevronRight, AlertTriangle } from 'lucide-react';

interface SlideProps { isActive: boolean; }

const EQUIPMENT = [
  {
    id: 'prompt',
    name: 'Prompt 提示词',
    icon: FileText,
    color: '#8B5CF6',
    desc: '把知识和指令写成上下文交给AI',
    detail: '所有知识和能力本质上都是通过上下文（Prompt）进入大模型的',
    effect: { C: 0, P: -15, U: -10 },
    problem: '但AI记不住太长的内容，效率低',
  },
  {
    id: 'rag',
    name: 'RAG + 知识图谱',
    icon: Search,
    color: '#3B82F6',
    desc: '需要时去查，不用全记住',
    detail: '不让AI死记硬背，而是按需检索精准知识',
    effect: { C: -5, P: 0, U: -15 },
    problem: '解决了"记不住"，但没解决"不会做"',
  },
  {
    id: 'func',
    name: 'Function-call',
    icon: Wrench,
    color: '#10B981',
    desc: '给AI成熟的系统工具权限',
    detail: '计算、查询交给确定性系统，AI只负责调度',
    effect: { C: -5, P: 0, U: -10 },
    problem: '工具有了，但流程还不固定',
  },
  {
    id: 'workflow',
    name: 'Workflow 工作流',
    icon: ClipboardList,
    color: '#F59E0B',
    desc: '固化标准业务流程',
    detail: '标准化流程自动执行，减少人工决策',
    effect: { C: -10, P: -20, U: -10 },
    problem: '开发的人就是用的人——说一句干一句，很累！P又上去了',
  },
];

const BASE_STATS = { C: 10, P: 70, U: 80 };

const Slide04_ThreeProblems: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [equipped, setEquipped] = useState(0);

  const currentStats = {
    C: BASE_STATS.C + EQUIPMENT.slice(0, equipped).reduce((s, e) => s + (e.effect.C || 0), 0),
    P: BASE_STATS.P + EQUIPMENT.slice(0, equipped).reduce((s, e) => s + (e.effect.P || 0), 0),
    U: BASE_STATS.U + EQUIPMENT.slice(0, equipped).reduce((s, e) => s + (e.effect.U || 0), 0),
  };

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      gsap.fromTo('.eq-title', { opacity: 0, y: -20 }, { opacity: 1, y: 0, duration: 0.6 });
      gsap.fromTo('.eq-base', { opacity: 0, scale: 0.9 }, { opacity: 1, scale: 1, duration: 0.5, ease: 'back.out(1.5)', delay: 0.3 });
      gsap.fromTo('.eq-slot', { opacity: 0, x: -20 },
        { opacity: 1, x: 0, duration: 0.4, stagger: 0.1, ease: 'power3.out', delay: 0.5 });
      gsap.fromTo('.eq-hint', { opacity: 0 }, { opacity: 1, duration: 0.4, delay: 1.0 });
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive] });

  const handleClick = () => {
    if (equipped < 4) {
      const idx = equipped;
      const slotEl = containerRef.current?.querySelector(`.eq-slot-${idx}`);
      const badgeEl = containerRef.current?.querySelector(`.eq-badge-${idx}`);

      const ctx = gsap.context(() => {
        gsap.to(slotEl, {
          scale: 1.05,
          duration: 0.15,
          yoyo: true,
          repeat: 1,
          ease: 'power2.inOut',
        });
        gsap.fromTo(badgeEl, { opacity: 0, scale: 0 },
          { opacity: 1, scale: 1, duration: 0.3, ease: 'back.out(2)', delay: 0.15 });
      }, containerRef);
      ctx.revert();

      setEquipped(equipped + 1);

      if (equipped + 1 === 4) {
        const ctx2 = gsap.context(() => {
          gsap.fromTo('.eq-summary', { opacity: 0, y: 20 },
            { opacity: 1, y: 0, duration: 0.5, ease: 'power3.out', delay: 0.5 });
        }, containerRef);
        ctx2.revert();
      }
    }
  };

  return (
    <section ref={containerRef}
      className="w-full min-h-[100dvh] flex flex-col items-center px-6 py-10 md:py-14 relative overflow-hidden cursor-pointer select-none"
      style={{ backgroundColor: 'var(--bg-primary)' }}
      onClick={handleClick}>

      {/* Title */}
      <h2 className="eq-title text-h1 font-bold text-[var(--text-primary)] mb-1 opacity-0">
        大模型的装备栏
      </h2>
      <p className="eq-title text-body text-[var(--text-secondary)] mb-4 opacity-0">
        法师（大模型）完备度低但覆盖面广。让我们一件件给它穿上装备，看 C·P·U 怎么变。
      </p>

      <div className="flex flex-col lg:flex-row gap-6 max-w-6xl w-full">
        {/* Left: Character + Stats */}
        <div className="eq-base lg:w-64 shrink-0 opacity-0">
          <div className="rounded-xl border-2 p-4 text-center mb-4" style={{ borderColor: '#8B5CF6', backgroundColor: '#8B5CF608' }}>
            <div className="w-16 h-16 rounded-full mx-auto mb-2 flex items-center justify-center" style={{ backgroundColor: '#8B5CF615' }}>
              <Sparkles size={32} style={{ color: '#8B5CF6' }} />
            </div>
            <span className="text-h3 font-bold" style={{ color: '#8B5CF6' }}>法师·规划者</span>
            <span className="text-caption text-[var(--text-secondary)] block mt-1">普通大模型</span>
          </div>

          {/* Live Stats */}
          <div className="rounded-xl border p-4" style={{ borderColor: 'var(--border)', backgroundColor: 'var(--bg-secondary)' }}>
            <span className="text-caption font-bold text-[var(--text-secondary)] mb-2 block">实时属性</span>
            {[
              { label: 'C', value: currentStats.C, color: 'var(--accent)', name: '完备度' },
              { label: 'P', value: currentStats.P, color: 'var(--primary)', name: '参与度' },
              { label: 'U', value: currentStats.U, color: 'var(--success)', name: '不确定度' },
            ].map((stat) => (
              <div key={stat.label} className="mb-2">
                <div className="flex justify-between text-caption mb-0.5">
                  <span className="font-bold" style={{ color: stat.color }}>{stat.label} {stat.name}</span>
                  <span className="font-mono" style={{ color: stat.color }}>{stat.value}</span>
                </div>
                <div className="h-2 rounded-full overflow-hidden" style={{ backgroundColor: `${stat.color}20` }}>
                  <div className="h-full rounded-full transition-all duration-700"
                    style={{ width: `${Math.max(0, stat.value)}%`, backgroundColor: stat.color }} />
                </div>
              </div>
            ))}
            <p className="text-caption text-[var(--text-light)] mt-2">装备 {equipped}/4</p>
          </div>
        </div>

        {/* Right: Equipment Slots */}
        <div className="flex-1 space-y-3">
          {EQUIPMENT.map((eq, i) => {
            const isActive = i < equipped;
            const Icon = eq.icon;
            return (
              <div key={eq.id}
                className={`eq-slot eq-slot-${i} rounded-xl border-2 p-4 transition-all duration-300 ${isActive ? '' : 'opacity-60'}`}
                style={{
                  borderColor: isActive ? eq.color : 'var(--border)',
                  backgroundColor: isActive ? `${eq.color}08` : 'var(--bg-secondary)',
                }}>
                <div className="flex items-start gap-3">
                  {/* Equipment icon */}
                  <div className="w-10 h-10 rounded-lg flex items-center justify-center shrink-0"
                    style={{ backgroundColor: `${eq.color}15`, color: isActive ? eq.color : 'var(--text-light)' }}>
                    <Icon size={20} />
                  </div>

                  {/* Equipment info */}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-body font-bold text-[var(--text-primary)]">{eq.name}</span>
                      {isActive && (
                        <span className={`eq-badge-${i} text-caption px-2 py-0.5 rounded-full font-semibold text-white opacity-0`}
                          style={{ backgroundColor: eq.color }}>
                          已装备
                        </span>
                      )}
                      {!isActive && equipped >= i && (
                        <span className="text-caption text-[var(--text-light)] animate-pulse">← 点击装备</span>
                      )}
                    </div>
                    <p className="text-caption text-[var(--text-secondary)]">{eq.desc}</p>
                    {isActive && (
                      <>
                        <p className="text-caption text-[var(--text-light)] mt-1 italic">{eq.detail}</p>
                        <div className="flex items-center gap-3 mt-2">
                          {eq.effect.C !== 0 && (
                            <span className="text-caption font-mono" style={{ color: eq.effect.C > 0 ? 'var(--accent)' : 'var(--success)' }}>
                              C{eq.effect.C > 0 ? '+' : ''}{eq.effect.C}
                            </span>
                          )}
                          {eq.effect.P !== 0 && (
                            <span className="text-caption font-mono" style={{ color: eq.effect.P > 0 ? 'var(--accent)' : 'var(--success)' }}>
                              P{eq.effect.P > 0 ? '+' : ''}{eq.effect.P}
                            </span>
                          )}
                          {eq.effect.U !== 0 && (
                            <span className="text-caption font-mono" style={{ color: eq.effect.U > 0 ? 'var(--accent)' : 'var(--success)' }}>
                              U{eq.effect.U > 0 ? '+' : ''}{eq.effect.U}
                            </span>
                          )}
                          <span className="text-caption" style={{ color: 'var(--accent)' }}>
                            <AlertTriangle size={10} className="inline mr-1" />{eq.problem}
                          </span>
                        </div>
                      </>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Summary after all equipped */}
      {equipped >= 4 && (
        <div className="eq-summary text-center max-w-2xl mt-4 opacity-0">
          <div className="rounded-xl border-2 p-4" style={{ borderColor: 'var(--accent)', backgroundColor: 'var(--accent)08' }}>
            <p className="text-body font-bold text-[var(--text-primary)]">
              降了 U（不确定度），但 P（参与度）又上去了！
            </p>
            <p className="text-caption text-[var(--text-secondary)] mt-1">
              不可能三角在起作用——Workflow让开发的人就是用的人，说一句干一句，操作成本（参与度）很高。
            </p>
          </div>
          <p className="text-caption text-[var(--text-light)] mt-3 animate-pulse flex items-center justify-center gap-1">
            <ChevronRight size={14} /> 下一页：OpenClaw 的终极升级
          </p>
        </div>
      )}

      {/* Bottom hint */}
      <div className="absolute bottom-6 text-caption text-[var(--text-light)]">
        {equipped < 4 ? `点击装备第 ${equipped + 1} 件装备` : '装备完成！进入下一页 →'}
      </div>
    </section>
  );
};

export default memo(Slide04_ThreeProblems);

