import React, { useRef, memo, useState } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { Brain, BookOpen, Cpu, Sparkles, Crown, AlertTriangle, Zap } from 'lucide-react';

interface SlideProps { isActive: boolean; }

const ADV_EQUIPMENT = [
  {
    id: 'react',
    name: 'ReAct 智能体范式',
    icon: Brain,
    color: '#EC4899',
    desc: '让AI自主规划→执行→反思',
    detail: '从"人指挥AI"变成"AI自己规划和决策"',
    effect: { C: 0, P: -30, U: +25 },
    problem: '上下文越长，注意力稀释越严重（30-40%准确率下降）',
  },
  {
    id: 'skills',
    name: 'Skills + MCP 渐进式加载',
    icon: BookOpen,
    color: '#3B82F6',
    desc: '只加载需要的技能，不一次全塞',
    detail: '解决注意力稀释：用到的才加载，上下文精简',
    effect: { C: 0, P: 0, U: -15 },
    problem: null,
  },
  {
    id: 'harness',
    name: 'Harness 记忆工程',
    icon: Cpu,
    color: '#10B981',
    desc: '每次对话后自动总结经验',
    detail: '下次直接调用记忆，减少重复劳动',
    effect: { C: -5, P: -5, U: -5 },
    problem: null,
  },
  {
    id: 'hermes',
    name: 'Hermes Agent 自动生成Skill',
    icon: Sparkles,
    color: '#F59E0B',
    desc: 'AI自动识别新模式并编写新Skill',
    detail: 'AI帮你开发，进一步降低开发成本',
    effect: { C: -10, P: 0, U: 0 },
    problem: null,
  },
];

const AFTER_BASIC = { C: -10, P: -35, U: -45 };
const BASE_STATS = { C: 10, P: 70, U: 80 };

const Slide05_MemoryProblem: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [equipped, setEquipped] = useState(0);

  const cumulEffect = (eqCount: number) => {
    let c = AFTER_BASIC.C, p = AFTER_BASIC.P, u = AFTER_BASIC.U;
    for (let i = 0; i < eqCount; i++) {
      c += ADV_EQUIPMENT[i].effect.C;
      p += ADV_EQUIPMENT[i].effect.P;
      u += ADV_EQUIPMENT[i].effect.U;
    }
    return {
      C: Math.max(0, BASE_STATS.C + c),
      P: Math.max(0, BASE_STATS.P + p),
      U: Math.max(0, BASE_STATS.U + u),
    };
  };

  const stats = cumulEffect(equipped);

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      gsap.fromTo('.adv-title', { opacity: 0, y: -20 }, { opacity: 1, y: 0, duration: 0.6 });
      gsap.fromTo('.adv-context', { opacity: 0 }, { opacity: 1, duration: 0.5, delay: 0.2 });
      gsap.fromTo('.adv-slot', { opacity: 0, x: -20 },
        { opacity: 1, x: 0, duration: 0.4, stagger: 0.1, ease: 'power3.out', delay: 0.4 });
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive] });

  const handleClick = () => {
    if (equipped < 4) {
      const idx = equipped;
      const ctx = gsap.context(() => {
        gsap.to(`.adv-slot-${idx}`, { scale: 1.05, duration: 0.15, yoyo: true, repeat: 1, ease: 'power2.inOut' });
        gsap.fromTo(`.adv-badge-${idx}`, { opacity: 0, scale: 0 },
          { opacity: 1, scale: 1, duration: 0.3, ease: 'back.out(2)', delay: 0.15 });
      }, containerRef);
      ctx.revert();
      setEquipped(equipped + 1);

      if (equipped + 1 === 4) {
        const ctx2 = gsap.context(() => {
          gsap.fromTo('.adv-reveal', { opacity: 0, scale: 0.8 },
            { opacity: 1, scale: 1, duration: 0.7, ease: 'back.out(2)', delay: 0.5 });
          gsap.fromTo('.adv-token-warning', { opacity: 0, y: 15 },
            { opacity: 1, y: 0, duration: 0.5, delay: 1.2 });
        }, containerRef);
        ctx2.revert();
      }
    }
  };

  return (
    <section ref={containerRef}
      className="w-full min-h-[100dvh] flex flex-col items-center px-6 py-10 md:py-14 relative overflow-hidden cursor-pointer select-none"
      style={{ backgroundColor: 'var(--bg-primary)' }}
      onClick={handleClick}>

      <h2 className="adv-title text-h1 font-bold text-[var(--text-primary)] mb-1 opacity-0">
        OpenClaw 的终极升级
      </h2>
      <p className="adv-context text-body text-[var(--text-secondary)] mb-4 opacity-0">
        上一页降了U但P又上去了。这次我们用更高级的装备——同时降低P和U
      </p>

      <div className="flex flex-col lg:flex-row gap-6 max-w-6xl w-full">
        {/* Left: Stats + Final Reveal */}
        <div className="lg:w-64 shrink-0">
          <div className="rounded-xl border p-4 mb-4" style={{ borderColor: 'var(--border)', backgroundColor: 'var(--bg-secondary)' }}>
            <span className="text-caption font-bold text-[var(--text-secondary)] mb-2 block">实时属性（含基础装备）</span>
            {[
              { label: 'C', value: stats.C, color: 'var(--accent)', name: '完备度' },
              { label: 'P', value: stats.P, color: 'var(--primary)', name: '参与度' },
              { label: 'U', value: stats.U, color: 'var(--success)', name: '不确定度' },
            ].map((stat) => (
              <div key={stat.label} className="mb-2 last:mb-0">
                <div className="flex justify-between text-caption mb-0.5">
                  <span className="font-bold" style={{ color: stat.color }}>{stat.label} {stat.name}</span>
                  <span className="font-mono" style={{ color: stat.color }}>{stat.value}</span>
                </div>
                <div className="h-2.5 rounded-full overflow-hidden" style={{ backgroundColor: `${stat.color}20` }}>
                  <div className="h-full rounded-full transition-all duration-700"
                    style={{ width: `${stat.value}%`, backgroundColor: stat.color }} />
                </div>
              </div>
            ))}
            <p className="text-caption text-[var(--text-light)] mt-3">高级装备 {equipped}/4</p>
          </div>

          {/* Final Reveal - OpenClaw character card */}
          {equipped >= 4 && (
            <div className="adv-reveal rounded-xl border-2 p-4 text-center opacity-0"
              style={{ borderColor: '#F59E0B', backgroundColor: '#F59E0B08', boxShadow: '0 0 20px #F59E0B20' }}>
              <div className="w-14 h-14 rounded-full mx-auto mb-2 flex items-center justify-center"
                style={{ backgroundColor: '#F59E0B20' }}>
                <Crown size={28} style={{ color: '#F59E0B' }} />
              </div>
              <span className="text-h3 font-bold" style={{ color: '#F59E0B' }}>OpenClaw 完全体</span>
              <div className="mt-3 space-y-1">
                {[
                  { label: 'C', value: stats.C, color: 'var(--accent)' },
                  { label: 'P', value: stats.P, color: 'var(--primary)' },
                  { label: 'U', value: stats.U, color: 'var(--success)' },
                ].map(s => (
                  <div key={s.label} className="flex justify-between text-caption">
                    <span className="font-bold" style={{ color: s.color }}>{s.label}</span>
                    <span className="font-mono font-bold" style={{ color: s.color }}>{s.value}</span>
                  </div>
                ))}
              </div>
              <span className="inline-flex items-center gap-1 mt-2 text-caption font-bold text-white px-2 py-1 rounded-full"
                style={{ backgroundColor: '#F59E0B' }}>
                <Crown size={12} /> 氪金玩家 · Token换智能
              </span>
            </div>
          )}
        </div>

        {/* Right: Advanced Equipment Slots */}
        <div className="flex-1 space-y-3">
          {ADV_EQUIPMENT.map((eq, i) => {
            const isEq = i < equipped;
            const isNext = i === equipped;
            const Icon = eq.icon;
            return (
              <div key={eq.id}
                className={`adv-slot adv-slot-${i} rounded-xl border-2 p-3 md:p-4 transition-all duration-300 ${isNext ? 'ring-2 ring-offset-1 animate-pulse' : ''}`}
                style={{
                  borderColor: isEq ? eq.color : isNext ? eq.color : 'var(--border)',
                  backgroundColor: isEq ? `${eq.color}08` : 'var(--bg-secondary)',
                }}>
                <div className="flex items-start gap-3">
                  <div className="w-9 h-9 rounded-lg flex items-center justify-center shrink-0"
                    style={{ backgroundColor: `${eq.color}15`, color: isEq ? eq.color : 'var(--text-light)' }}>
                    <Icon size={18} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-0.5 flex-wrap">
                      <span className="text-body-sm font-bold text-[var(--text-primary)]">{eq.name}</span>
                      {isEq && (
                        <span className={`adv-badge-${i} text-caption px-1.5 py-0.5 rounded-full font-semibold text-white opacity-0`}
                          style={{ backgroundColor: eq.color }}>已装备</span>
                      )}
                      {isNext && <span className="text-caption text-[var(--text-light)]">← 点击装备</span>}
                    </div>
                    <p className="text-caption text-[var(--text-secondary)]">{eq.desc}</p>
                    {isEq && (
                      <div className="mt-1.5 flex items-center gap-3 flex-wrap">
                        <p className="text-caption text-[var(--text-light)] italic">{eq.detail}</p>
                        <div className="flex items-center gap-2">
                          {eq.effect.C !== 0 && <span className="text-caption font-mono font-bold" style={{ color: eq.effect.C > 0 ? 'var(--accent)' : 'var(--success)' }}>C{eq.effect.C > 0 ? '+' : ''}{eq.effect.C}</span>}
                          {eq.effect.P !== 0 && <span className="text-caption font-mono font-bold" style={{ color: eq.effect.P > 0 ? 'var(--accent)' : 'var(--success)' }}>P{eq.effect.P > 0 ? '+' : ''}{eq.effect.P}</span>}
                          {eq.effect.U !== 0 && <span className="text-caption font-mono font-bold" style={{ color: eq.effect.U > 0 ? 'var(--accent)' : 'var(--success)' }}>U{eq.effect.U > 0 ? '+' : ''}{eq.effect.U}</span>}
                          {eq.problem && (
                            <span className="text-caption flex items-center gap-0.5" style={{ color: 'var(--accent)' }}>
                              <AlertTriangle size={10} /> {eq.problem}
                            </span>
                          )}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            );
          })}

          {/* Token hidden cost warning */}
          {equipped >= 4 && (
            <div className="adv-token-warning rounded-xl border-2 p-4 opacity-0"
              style={{ borderColor: '#EF4444', backgroundColor: '#EF444408' }}>
              <div className="flex items-start gap-2">
                <AlertTriangle size={18} style={{ color: '#EF4444' }} className="shrink-0 mt-0.5" />
                <div>
                  <span className="text-body-sm font-bold" style={{ color: '#EF4444' }}>隐性成本：Token + 模型智能上限</span>
                  <p className="text-caption text-[var(--text-secondary)] mt-1">
                    OpenClaw的总人力成本确实降低了，但Token（算力）成本是新的隐性维度。
                    且模型的智能引入有上限——如果没有更聪明的大模型，已达上限的不确定度就只能转移到确认成本（人工校验）上。
                  </p>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="absolute bottom-6 text-caption text-[var(--text-light)]">
        {equipped < 4 ? `点击装备第 ${equipped + 1} 件高级装备` : 'OpenClaw 完全体！翻页继续 →'}
      </div>
    </section>
  );
};

export default memo(Slide05_MemoryProblem);

