import React, { useRef, memo, useState } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { GraduationCap, Brain, BookOpen, Bot, MessageSquare, Search, Wrench, ClipboardList, AlertTriangle, ChevronRight } from 'lucide-react';

interface SlideProps { isActive: boolean; }

const PROBLEMS = [
  { icon: Brain, title: '记不住', desc: '上下文记忆能力有限，信息过载', color: 'var(--primary)' },
  { icon: BookOpen, title: '不懂业务', desc: '没有公司业务知识和流程', color: 'var(--success)' },
  { icon: Bot, title: '没有手脚', desc: '无法精确执行操作和调用系统', color: 'var(--accent)' },
];

const EQUIPMENT = [
  { id: 'prompt', name: 'Prompt 提示词', icon: MessageSquare, color: '#8B5CF6', desc: '所有知识、能力都通过上下文进入大模型', effect: 'C:0  P:-15  U:-10', problem: 'AI记不住太长内容，效率低' },
  { id: 'rag', name: 'RAG + 知识图谱', icon: Search, color: '#3B82F6', desc: '需要时去查，不用全记住', effect: 'C:-5  P:0  U:-15', problem: '解决了"记不住"，但没解决"不会做"' },
  { id: 'func', name: 'Function-call', icon: Wrench, color: '#10B981', desc: '给AI成熟的系统工具权限', effect: 'C:-5  P:0  U:-10', problem: '工具有了，但流程不固定' },
  { id: 'workflow', name: 'Workflow 工作流', icon: ClipboardList, color: '#F59E0B', desc: '固化标准业务流程', effect: 'C:-10  P:-20  U:-10', problem: '使用者=开发者，说一句干一句，很累！' },
];

const Slide04_ThreeProblems: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [phase, setPhase] = useState(0);

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      gsap.fromTo('.intro-title', { opacity: 0, y: -20 }, { opacity: 1, y: 0, duration: 0.6 });
      gsap.fromTo('.intro-profile', { opacity: 0, scale: 0.9 }, { opacity: 1, scale: 1, duration: 0.5, ease: 'back.out(1.5)', delay: 0.3 });
      gsap.fromTo('.intro-problem', { opacity: 0, x: -20 },
        { opacity: 1, x: 0, duration: 0.4, stagger: 0.12, delay: 0.6 });
      gsap.fromTo('.intro-hint', { opacity: 0 }, { opacity: 1, duration: 0.4, delay: 1.2 });
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive] });

  const handleClick = () => {
    if (phase === 0) {
      const ctx = gsap.context(() => {
        gsap.to('.intro-profile', { opacity: 0, y: -20, duration: 0.4 });
        gsap.to('.intro-problem', { opacity: 0, x: 20, duration: 0.3, stagger: 0.05 });
        gsap.to('.intro-hint', { opacity: 0, duration: 0.2 });
        gsap.fromTo('.eq-section', { opacity: 0, y: 30 }, { opacity: 1, y: 0, duration: 0.5, ease: 'power3.out', delay: 0.5 });
        gsap.fromTo('.eq-slot', { opacity: 0, x: -20 },
          { opacity: 1, x: 0, duration: 0.4, stagger: 0.1, ease: 'power3.out', delay: 0.7 });
      }, containerRef);
      ctx.revert();
      setPhase(1);
    } else if (phase === 1) {
      const ctx = gsap.context(() => {
        gsap.to('.eq-slot', { opacity: 0.4, duration: 0.3 });
        gsap.fromTo('.eq-summary', { opacity: 0, y: 20 },
          { opacity: 1, y: 0, duration: 0.5, ease: 'power3.out', delay: 0.3 });
      }, containerRef);
      ctx.revert();
      setPhase(2);
    } else {
      setPhase(0);
    }
  };

  return (
    <section ref={containerRef}
      className="w-full min-h-[100dvh] flex flex-col items-center px-6 py-10 md:py-14 relative overflow-hidden cursor-pointer select-none"
      style={{ backgroundColor: 'var(--bg-primary)' }}
      onClick={handleClick}>

      <h2 className="intro-title text-h1 font-bold text-[var(--text-primary)] mb-2 opacity-0">
        聪明的应届生入职了
      </h2>
      <p className="intro-title text-body text-[var(--text-secondary)] mb-6 opacity-0">
        按我们去年的介绍，大模型就像一个刚招进来的清北应届生——聪明，但什么都不知道
      </p>

      {/* Phase 0: Profile + Problems */}
      {phase === 0 && (
        <>
          {/* Employee Profile Card */}
          <div className="intro-profile rounded-xl border-2 p-5 max-w-md w-full mb-6 opacity-0"
            style={{ borderColor: '#8B5CF6', backgroundColor: '#8B5CF608' }}>
            <div className="flex items-center gap-3 mb-3">
              <div className="w-12 h-12 rounded-full flex items-center justify-center" style={{ backgroundColor: '#8B5CF615' }}>
                <GraduationCap size={24} style={{ color: '#8B5CF6' }} />
              </div>
              <div>
                <span className="text-body font-bold text-[var(--text-primary)]">LLM 大模型</span>
                <span className="text-caption text-[var(--text-secondary)] block">清华应届生 · 通用能力极强</span>
              </div>
            </div>
            <div className="flex gap-4 text-caption">
              <span><span className="font-bold" style={{ color: 'var(--accent)' }}>C 完备度</span> 10（开发成本极低）</span>
              <span><span className="font-bold" style={{ color: 'var(--primary)' }}>P 参与度</span> 70（操作成本高）</span>
              <span><span className="font-bold" style={{ color: 'var(--success)' }}>U 不确定度</span> 80（会胡说）</span>
            </div>
          </div>

          {/* 3 Core Problems */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 max-w-4xl w-full">
            {PROBLEMS.map((p, i) => {
              const Icon = p.icon;
              return (
                <div key={i} className="intro-problem rounded-xl border-2 p-4 opacity-0"
                  style={{ borderColor: p.color, backgroundColor: `${p.color}08` }}>
                  <div className="w-10 h-10 rounded-lg flex items-center justify-center mb-3"
                    style={{ backgroundColor: `${p.color}15` }}>
                    <Icon size={20} style={{ color: p.color }} />
                  </div>
                  <h3 className="text-body font-bold mb-1" style={{ color: p.color }}>{p.title}</h3>
                  <p className="text-caption text-[var(--text-secondary)]">{p.desc}</p>
                </div>
              );
            })}
          </div>
          <p className="intro-hint text-body text-[var(--text-light)] mt-6 opacity-0">
            天然不知道我们的业务知识，会胡说。那么——怎么教他？点击继续 →
          </p>
        </>
      )}

      {/* Phase 1: Equipment Progression */}
      {phase === 1 && (
        <div className="eq-section max-w-3xl w-full opacity-0">
          <div className="rounded-xl border-2 p-4 mb-5" style={{ borderColor: '#8B5CF620', backgroundColor: '#8B5CF605' }}>
            <p className="text-body text-[var(--text-primary)]">
              <span className="font-bold" style={{ color: '#8B5CF6' }}>关键认知：</span>
              所有知识、能力、指令，都是通过<span className="font-bold">上下文（Prompt）</span>进入大模型的。
              我们能做的，就是用不同的方式把"上下文"喂给它。
            </p>
          </div>

          <div className="space-y-3">
            {EQUIPMENT.map((eq) => {
              const Icon = eq.icon;
              return (
                <div key={eq.id} className="eq-slot rounded-xl border-2 p-4 opacity-0"
                  style={{ borderColor: eq.color, backgroundColor: `${eq.color}06` }}>
                  <div className="flex items-start gap-3">
                    <div className="w-9 h-9 rounded-lg flex items-center justify-center shrink-0"
                      style={{ backgroundColor: `${eq.color}15`, color: eq.color }}>
                      <Icon size={18} />
                    </div>
                    <div className="flex-1">
                      <span className="text-body-sm font-bold text-[var(--text-primary)]">{eq.name}</span>
                      <p className="text-caption text-[var(--text-secondary)] mt-0.5">{eq.desc}</p>
                      <div className="flex items-center gap-3 mt-1.5 flex-wrap">
                        <span className="text-caption font-mono font-bold" style={{ color: 'var(--success)' }}>{eq.effect}</span>
                        <span className="text-caption flex items-center gap-0.5" style={{ color: 'var(--accent)' }}>
                          <AlertTriangle size={10} /> {eq.problem}
                        </span>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Phase 2: Summary — impossible triangle strikes */}
      {phase === 2 && (
        <div className="eq-summary max-w-2xl w-full text-center opacity-0">
          <div className="rounded-xl border-2 p-6 mb-4" style={{ borderColor: 'var(--accent)', backgroundColor: 'var(--accent)08' }}>
            <AlertTriangle size={28} className="mx-auto mb-3" style={{ color: 'var(--accent)' }} />
            <h3 className="text-h2 font-bold text-[var(--text-primary)] mb-2">
              U（不确定度）降了，但 P（参与度）又上去了！
            </h3>
            <p className="text-body text-[var(--text-secondary)]">
              Workflow 让开发者和使用者变成了同一个人——<br />
              说一句干一句，实习生很听话，但不会自主思考。<br />
              <span className="font-bold" style={{ color: 'var(--accent)' }}>不可能三角在起作用。</span>
            </p>
          </div>

          <div className="rounded-xl border p-4 mb-4" style={{ borderColor: 'var(--border)', backgroundColor: 'var(--bg-secondary)' }}>
            <p className="text-body font-bold text-[var(--text-primary)] mb-2">
              💡 金句：使用者的轻松，来自多方的投入
            </p>
            <p className="text-caption text-[var(--text-secondary)]">
              用户界面简单，不代表系统简单。背后是IT部门、开发工具、持续优化的综合结果。
            </p>
          </div>

          <p className="text-caption text-[var(--text-light)] animate-pulse flex items-center justify-center gap-1">
            <ChevronRight size={14} /> 下一页：能不能让AI自己思考和行动？
          </p>
        </div>
      )}

      <div className="absolute bottom-6 text-caption text-[var(--text-light)]">
        {phase === 0 ? '点击继续' : phase === 1 ? '点击查看总结' : '点击重置'}
      </div>
    </section>
  );
};

export default memo(Slide04_ThreeProblems);

