import React, { useRef, memo } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { Shield, Eye, Sparkles, ClipboardList } from 'lucide-react';

interface SlideProps { isActive: boolean; }

interface CharStats {
  C: number;
  P: number;
  U: number;
  special: string;
  specialDesc: string;
  pro: string;
  con: string;
}

interface Character {
  name: string;
  classType: string;
  mode: string;
  color: string;
  icon: React.ReactNode;
  stats: CharStats;
  imgPrompt: string;
}

const CHARACTERS: Character[] = [
  {
    name: '传统代码开发',
    classType: '【坚盾职业】执行者',
    mode: '执行',
    color: '#3B82F6',
    icon: <Shield size={24} />,
    stats: {
      C: 90, P: 15, U: 5,
      special: '绝对确定性',
      specialDesc: '逻辑完全可控，输出零偏差',
      pro: '结果100%可预测，边界清晰',
      con: '开发周期长，灵活性极低',
    },
    imgPrompt: 'A stoic medieval knight in full plate armor holding a massive tower shield, standing firm on a castle wall. Blue color theme. The shield has circuit board patterns etched into it. RPG character portrait style, dark fantasy, detailed digital art, clean background',
  },
  {
    name: '传统机器学习',
    classType: '【游侠职业】判断者',
    mode: '判断',
    color: '#10B981',
    icon: <Eye size={24} />,
    stats: {
      C: 60, P: 35, U: 30,
      special: '经验封装',
      specialDesc: '将大量分析经验固化为模型',
      pro: '可处理非结构化数据，有一定泛化能力',
      con: '需要大量标注数据，场景迁移成本高',
    },
    imgPrompt: 'A wise ranger archer with a glowing green eye, standing in a forest of data streams. The ranger holds a bow that fires arrows of light tracing prediction curves. Green color theme. RPG character portrait style, fantasy digital art, clean background',
  },
  {
    name: '普通大模型',
    classType: '【法师职业】规划者',
    mode: '规划',
    color: '#8B5CF6',
    icon: <Sparkles size={24} />,
    stats: {
      C: 10, P: 70, U: 80,
      special: '通用智能',
      specialDesc: '涌现出跨领域的推理规划能力',
      pro: '零门槛使用，覆盖面极广',
      con: '不确定性极高，结果不可控',
    },
    imgPrompt: 'A powerful wizard with swirling cosmic energy and nebula around their hands, purple arcane runes floating in the air. The wizard has an unpredictable, chaotic aura. Purple color theme. RPG character portrait style, fantasy digital art, clean background',
  },
  {
    name: '工作流/低代码开发',
    classType: '【工匠职业】调度者',
    mode: '执行+调度',
    color: '#F97316',
    icon: <ClipboardList size={24} />,
    stats: {
      C: 70, P: 50, U: 10,
      special: '流程确定性',
      specialDesc: '标准化流程保证输出高度确定',
      pro: '可视化配置，不需要写代码',
      con: '使用者=开发者，操作成本众包给用户',
    },
    imgPrompt: 'A skilled craftsman artisan working at a workshop bench with modular puzzle-piece components, assembling a complex mechanism. Orange color theme. The craftsman wears a toolbelt with visual flow-chart patterns. RPG character portrait style, fantasy digital art, clean background',
  },
];

function StatBar({ label, value, max, color }: { label: string; value: number; max: number; color: string }) {
  const pct = (value / max) * 100;
  return (
    <div className="flex items-center gap-2 mb-1.5">
      <span className="text-caption font-bold w-5 text-right" style={{ color }}>{label}</span>
      <div className="flex-1 h-3 rounded-full overflow-hidden" style={{ backgroundColor: `${color}20` }}>
        <div className="h-full rounded-full transition-all duration-700"
          style={{ width: `${pct}%`, backgroundColor: color }} />
      </div>
      <span className="text-caption font-mono w-7 text-right" style={{ color }}>{value}</span>
    </div>
  );
}

function CharCard({ char }: { char: Character }) {
  return (
    <div className="game-card relative rounded-xl border-2 p-4 md:p-5 w-full transition-all duration-500"
      style={{ borderColor: char.color, backgroundColor: `${char.color}06`, boxShadow: `${char.color}10` }}>
      {/* Header */}
      <div className="flex items-center gap-2 mb-3">
        <div className="w-9 h-9 rounded-lg flex items-center justify-center" style={{ backgroundColor: `${char.color}15`, color: char.color }}>
          {char.icon}
        </div>
        <div className="flex-1 min-w-0">
          <span className="text-body font-bold text-[var(--text-primary)] block truncate">{char.name}</span>
          <span className="text-caption" style={{ color: char.color }}>{char.classType}</span>
        </div>
      </div>

      {/* Image placeholder */}
      <div className="w-full h-24 md:h-28 rounded-lg mb-3 flex items-center justify-center border border-dashed overflow-hidden"
        style={{ borderColor: `${char.color}40`, backgroundColor: `${char.color}05` }}>
        <span className="text-caption text-center px-2 text-[var(--text-light)] italic">[图片占位]</span>
      </div>

      {/* Stats */}
      <div className="mb-3">
        <StatBar label="C" value={char.stats.C} max={100} color="var(--accent)" />
        <StatBar label="P" value={char.stats.P} max={100} color="var(--primary)" />
        <StatBar label="U" value={char.stats.U} max={100} color="var(--success)" />
      </div>

      {/* Legend */}
      <div className="flex gap-2 mb-3 text-caption text-[var(--text-light)]">
        <span>C=完备度</span><span>P=参与度</span><span>U=不确定度</span>
      </div>

      {/* Special ability */}
      <div className="rounded-lg px-3 py-2 mb-2" style={{ backgroundColor: `${char.color}10` }}>
        <div className="flex items-center gap-1.5 mb-0.5">
          <Sparkles size={12} style={{ color: char.color }} />
          <span className="text-caption font-bold" style={{ color: char.color }}>{char.stats.special}</span>
        </div>
        <span className="text-caption text-[var(--text-secondary)]">{char.stats.specialDesc}</span>
      </div>

      {/* Pro / Con */}
      <div className="space-y-1 text-caption">
        <div className="flex gap-1.5">
          <span className="text-[var(--success)] shrink-0">+</span>
          <span className="text-[var(--text-secondary)]">{char.stats.pro}</span>
        </div>
        <div className="flex gap-1.5">
          <span className="text-[var(--accent)] shrink-0">−</span>
          <span className="text-[var(--text-secondary)]">{char.stats.con}</span>
        </div>
      </div>
    </div>
  );
}

const Slide03_Ecosystem: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      gsap.fromTo('.game-title', { opacity: 0, y: -20 }, { opacity: 1, y: 0, duration: 0.6 });
      gsap.fromTo('.game-subtitle', { opacity: 0 }, { opacity: 1, duration: 0.5, delay: 0.3 });
      gsap.fromTo('.game-card', { opacity: 0, y: 30, scale: 0.95 },
        { opacity: 1, y: 0, scale: 1, duration: 0.5, stagger: 0.15, ease: 'back.out(1.5)', delay: 0.5 });
      gsap.fromTo('.game-bridge', { opacity: 0, y: 10 },
        { opacity: 1, y: 0, duration: 0.5, delay: 1.2 });
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive] });

  return (
    <section ref={containerRef}
      className="w-full min-h-[100dvh] flex flex-col items-center px-6 py-10 md:py-14 relative overflow-hidden"
      style={{ backgroundColor: 'var(--bg-primary)' }}>

      <h2 className="game-title text-h1 font-bold text-[var(--text-primary)] mb-1 opacity-0">
        游戏加点：职业图鉴
      </h2>
      <p className="game-subtitle text-body text-[var(--text-secondary)] mb-6 opacity-0">
        三种思维模式，对应三种「职业」 — 每个都有不同的 C·P·U 加点策略
      </p>

      {/* Stat legend */}
      <div className="flex gap-4 mb-6 text-caption">
        <span className="flex items-center gap-1"><span className="font-bold" style={{ color: 'var(--accent)' }}>C</span> 完备度（开发成本）</span>
        <span className="flex items-center gap-1"><span className="font-bold" style={{ color: 'var(--primary)' }}>P</span> 参与度（操作成本）</span>
        <span className="flex items-center gap-1"><span className="font-bold" style={{ color: 'var(--success)' }}>U</span> 不确定度（确认成本）</span>
      </div>

      {/* Character cards grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3 max-w-6xl w-full">
        {CHARACTERS.map((char, i) => (
          <div key={i} className="game-card opacity-0">
            <CharCard char={char} />
          </div>
        ))}
      </div>

      {/* Bridge to next slide */}
      <div className="game-bridge text-center mt-6 opacity-0">
        <p className="text-h3 font-bold text-[var(--text-primary)]">
          四种职业，四种加点策略 —— 但都绕不开不可能三角
        </p>
        <p className="text-body text-[var(--text-secondary)] mt-2">
          接下来，让我们看看"法师"（大模型）如何一步步穿上装备
        </p>
      </div>
    </section>
  );
};

export default memo(Slide03_Ecosystem);

