            {[
              { label: 'C 完备度', val: 50, color: 'var(--accent)' },
              { label: 'P 参与度', val: 8, color: 'var(--primary)' },
              { label: 'U 不确定度', val: 15, color: 'var(--success)' },
            ].map(s => (
