      )}

      {/* Phase 2: Compressed Architecture (Gateway/Node/Channel) */}
      {phase >= 2 && (
        <div className="rv-arch max-w-4xl w-full mt-4 opacity-0">
          <p className="text-body text-[var(--text-secondary)] mb-3 text-center">
