import React, { useRef, memo, useState } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { GitBranch, Cpu, Smartphone, Shield, Zap, Eye, BarChart3, ArrowRight } from 'lucide-react';

interface SlideProps { isActive: boolean; }

const ARCH = [
  {
    name: 'Gateway',
    subtitle: '通信枢纽 — AI 世界的 API Gateway',
    icon: GitBranch,
    color: '#3B82F6',
    desc: '所有 AI 通信统一经过 Gateway 转发',
    benefits: [
      { title: '清晰可追溯', desc: '每一条 AI 请求和响应都有完整记录，出了问题能定位', icon: Eye },
      { title: '可控可审计', desc: '可以拦截、过滤、限流，满足企业合规要求', icon: Shield },
      { title: '协议标准化', desc: '不同 AI 服务统一接口，后端切换模型无感', icon: GitBranch },
    ],
    beforeNoGateway: '每个工具直接调 AI API，通信混乱、无法追踪、安全风险高',
    afterGateway: '所有通信走 Gateway，日志完整、权限统一、可随时切换模型',
  },
  {
    name: 'Node',
    subtitle: '执行节点 — 让 AI 操作确定性更强',
    icon: Cpu,
    color: '#10B981',
    desc: '将 AI 的操作封装为标准化节点',
    benefits: [
      { title: '可规划', desc: '每个节点输入输出明确，流程可以提前设计', icon: BarChart3 },
      { title: '确定性更强', desc: '节点执行结果可预测，减少随机性', icon: Shield },
      { title: '性能更好', desc: '节点可以并行执行、缓存结果、按需加载', icon: Zap },
    ],
    beforeNoNode: 'AI 每次操作都是黑盒，不可预测、不可优化、串行等待',
    afterNode: '操作封装为节点，可规划、可缓存、可并行，确定性大幅提升',
  },
  {
    name: 'Channel',
    subtitle: '用户通道 — 让用户零门槛接入',
    icon: Smartphone,
    color: '#F59E0B',
    desc: '打通各种用户触达渠道',
    benefits: [
      { title: '多渠道接入', desc: '企业微信、飞书、钉钉、邮件、网页一键接入', icon: Smartphone },
      { title: '统一体验', desc: '不管哪个渠道进来，AI 的能力和记忆完全一致', icon: GitBranch },
      { title: '用户无感', desc: '用户不需要知道背后是哪个模型，只管用', icon: Eye },
    ],
    beforeNoChannel: '每个 AI 能力需要单独开发前端和接入层，重复造轮子',
    afterChannel: '一个 Channel 配置搞定所有渠道，用户使用体验统一',
  },
];

const Slide09_OpenClawArch: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [expanded, setExpanded] = useState<number | null>(null);

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      gsap.fromTo('.arch-title', { opacity: 0, y: -20 }, { opacity: 1, y: 0, duration: 0.6 });
      gsap.fromTo('.arch-subtitle', { opacity: 0 }, { opacity: 1, duration: 0.5, delay: 0.2 });
      gsap.fromTo('.arch-card', { opacity: 0, y: 25 },
        { opacity: 1, y: 0, duration: 0.5, stagger: 0.15, ease: 'back.out(1.3)', delay: 0.4 });
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive] });

  useGSAP(() => {
    if (!isActive || expanded === null) return;
    const ctx = gsap.context(() => {
      gsap.fromTo('.arch-benefit', { opacity: 0, x: -10 },
        { opacity: 1, x: 0, duration: 0.3, stagger: 0.08, delay: 0.1 });
      gsap.fromTo('.arch-compare', { opacity: 0, y: 10 },
        { opacity: 1, y: 0, duration: 0.4, delay: 0.3 });
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive, expanded] });

  return (
    <section ref={containerRef}
      className="w-full min-h-[100dvh] flex flex-col items-center px-6 py-10 md:py-14 relative overflow-hidden"
      style={{ backgroundColor: 'var(--bg-primary)' }}>

      <h2 className="arch-title text-h1 font-bold text-[var(--text-primary)] mb-1 opacity-0">
        OpenClaw 三大架构创新
      </h2>
      <p className="arch-subtitle text-body text-[var(--text-secondary)] mb-5 max-w-2xl text-center opacity-0">
        除了核心装备，这三大架构设计让 OpenClaw 从"能用"变成了"火爆"。点击卡片展开详情。
      </p>

      <div className="max-w-5xl w-full space-y-4">
        {ARCH.map((item, i) => {
          const Icon = item.icon;
          const isExp = expanded === i;
          return (
            <div key={i}
              className={`arch-card rounded-xl border-2 p-4 md:p-5 cursor-pointer transition-all duration-300 ${isExp ? 'ring-2 ring-offset-1' : ''}`}
              style={{
                borderColor: isExp ? item.color : `${item.color}60`,
                backgroundColor: isExp ? `${item.color}08` : `${item.color}04`,
              }}
              onClick={(e) => { e.stopPropagation(); setExpanded(isExp ? null : i); }}>
              {/* Header */}
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-lg flex items-center justify-center shrink-0"
                  style={{ backgroundColor: `${item.color}15`, color: item.color }}>
                  <Icon size={20} />
                </div>
                <div className="flex-1">
                  <div className="flex items-center gap-2">
                    <span className="text-body font-bold" style={{ color: item.color }}>{item.name}</span>
                    <span className="text-caption text-[var(--text-light)]">{item.subtitle}</span>
                  </div>
                  <p className="text-caption text-[var(--text-secondary)] mt-0.5">{item.desc}</p>
                </div>
                {!isExp && <ArrowRight size={16} style={{ color: item.color }} className="shrink-0" />}
              </div>

              {/* Expanded: Benefits + Comparison */}
              {isExp && (
                <div className="mt-4">
