import React, { useRef, memo, useState } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { GitBranch, Cpu, Smartphone, Shield, Zap, Eye, BarChart3, ArrowRight } from 'lucide-react';

interface SlideProps { isActive: boolean; }

const ARCH = [
  {
    name: 'Gateway',
    subtitle: '通信枢纽 — AI 世界的 API Gateway',
