  },
  {
    name: 'Node',
    subtitle: '执行节点 — 让 AI 操作确定性更强',
    icon: Cpu,
    color: '#10B981',
    desc: '将 AI 的操作封装为标准化节点',
    benefits: [
      { title: '可规划', desc: '每个节点输入输出明确，流程可以提前设计', icon: BarChart3 },
      { title: '确定性更强', desc: '节点执行结果可预测，减少随机性', icon: Shield },
      { title: '性能更好', desc: '节点可以并行执行、缓存结果、按需加载', icon: Zap },
    ],
    beforeNoNode: 'AI 每次操作都是黑盒，不可预测、不可优化、串行等待',
