  },
  {
    name: 'Channel',
    subtitle: '用户通道 — 让用户零门槛接入',
    icon: Smartphone,
    color: '#F59E0B',
    desc: '打通各种用户触达渠道',
    benefits: [
      { title: '多渠道接入', desc: '企业微信、飞书、钉钉、邮件、网页一键接入', icon: Smartphone },
      { title: '统一体验', desc: '不管哪个渠道进来，AI 的能力和记忆完全一致', icon: GitBranch },
      { title: '用户无感', desc: '用户不需要知道背后是哪个模型，只管用', icon: Eye },
    ],
    beforeNoChannel: '每个 AI 能力需要单独开发前端和接入层，重复造轮子',
    afterChannel: '一个 Channel 配置搞定所有渠道，用户使用体验统一',
  },
];

const Slide09_OpenClawArch: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [expanded, setExpanded] = useState<number | null>(null);

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      gsap.fromTo('.arch-title', { opacity: 0, y: -20 }, { opacity: 1, y: 0, duration: 0.6 });
      gsap.fromTo('.arch-subtitle', { opacity: 0 }, { opacity: 1, duration: 0.5, delay: 0.2 });
      gsap.fromTo('.arch-card', { opacity: 0, y: 25 },
        { opacity: 1, y: 0, duration: 0.5, stagger: 0.15, ease: 'back.out(1.3)', delay: 0.4 });
