              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-lg flex items-center justify-center shrink-0"
                  style={{ backgroundColor: `${item.color}15`, color: item.color }}>
                  <Icon size={20} />
                </div>
                <div className="flex-1">
                  <div className="flex items-center gap-2">
                    <span className="text-body font-bold" style={{ color: item.color }}>{item.name}</span>
                    <span className="text-caption text-[var(--text-light)]">{item.subtitle}</span>
                  </div>
                  <p className="text-caption text-[var(--text-secondary)] mt-0.5">{item.desc}</p>
                </div>
                {!isExp && <ArrowRight size={16} style={{ color: item.color }} className="shrink-0" />}
              </div>

              {/* Expanded: Benefits + Comparison */}
              {isExp && (
                <div className="mt-4">
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-2 mb-3">
                    {item.benefits.map((b, j) => {
                      const BIcon = b.icon;
                      return (
                        <div key={j} className="arch-benefit rounded-lg border p-3"
                          style={{ borderColor: `${item.color}30`, backgroundColor: `${item.color}06` }}>
                          <div className="flex items-center gap-1.5 mb-1">
                            <BIcon size={14} style={{ color: item.color }} />
                            <span className="text-caption font-bold" style={{ color: item.color }}>{b.title}</span>
