                  </div>
                  <div className="arch-compare grid grid-cols-2 gap-2">
                    <div className="rounded-lg p-3" style={{ backgroundColor: 'var(--bg-secondary)' }}>
                      <span className="text-caption font-bold text-[var(--accent)]">❌ 没有 {item.name}</span>
                      <p className="text-caption text-[var(--text-secondary)] mt-0.5">{item.beforeNoGateway}</p>
                    </div>
                    <div className="rounded-lg p-3" style={{ backgroundColor: `${item.color}06` }}>
                      <span className="text-caption font-bold" style={{ color: item.color }}>✅ 有 {item.name}</span>
                      <p className="text-caption text-[var(--text-secondary)] mt-0.5">{item.afterGateway}</p>
                    </div>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <p className="text-caption text-[var(--text-light)] mt-5">
        这三大架构 + 之前的8件装备 = OpenClaw 火爆的完整原因
      </p>
