import React, { useRef, memo, useState, useMemo } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { HelpCircle, Cpu, Sparkles, Brain, Bot, Code2, Wrench, MessageSquare, BookOpen, Layers, Zap, Search, Database, GitBranch, Terminal, Puzzle, Eye, Workflow, Settings2 } from 'lucide-react';

interface SlideProps { isActive: boolean; }

const TAGS = [
  { text: 'AI Model', icon: Brain },
  { text: 'Prompt', icon: MessageSquare },
  { text: 'RAG', icon: Search },
  { text: 'Workflow', icon: Workflow },
  { text: 'Agent', icon: Bot },
  { text: 'ReAct', icon: Zap },
  { text: 'Skill', icon: Puzzle },
  { text: 'Hermes Agent', icon: Sparkles },
  { text: 'Claude Code', icon: Terminal },
  { text: 'OpenClaw', icon: Code2 },
  { text: 'Harness Eng.', icon: Wrench },
  { text: 'MCP', icon: Plug },
  { text: 'Fine-tuning', icon: Settings2 },
  { text: 'Function Call', icon: GitBranch },
  { text: 'Embedding', icon: Layers },
  { text: 'Vector DB', icon: Database },
  { text: 'Vibe Coding', icon: Sparkles },
  { text: 'Coze', icon: Layers },
  { text: 'Dify', icon: Layers },
  { text: 'Manus', icon: Eye },
  { text: 'Copilot', icon: Cpu },
  { text: 'Tool Use', icon: Wrench },
  { text: 'Few-shot', icon: BookOpen },
  { text: 'AutoGPT', icon: Bot },
];

function Plug(props: React.SVGProps<SVGSVGElement> & { size?: number }) {
  return (
    <svg xmlns="http://www.w3.org/2000/svg" width={props.size || 24} height={props.size || 24} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round" {...props}>
      <path d="M12 22v-5"/><path d="M9 8V2"/><path d="M15 8V2"/><path d="M18 8v5a6 6 0 0 1-12 0V8z"/>
    </svg>
  );
}

const COLORS = [
  'var(--primary)', 'var(--accent)', 'var(--secondary)',
  'var(--success)', 'var(--text-secondary)', '#8B5CF6', '#EC4899',
];

function seededRandom(seed: number) {
  const x = Math.sin(seed * 9301 + 49297) * 233280;
  return x - Math.floor(x);
}

const Slide01_Cover: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [phase, setPhase] = useState(0);

  const tagPositions = useMemo(() =>
    TAGS.map((_, i) => ({
      x: (seededRandom(i * 7 + 1) - 0.5) * 80,
      y: (seededRandom(i * 13 + 3) - 0.5) * 65,
      rot: (seededRandom(i * 11 + 5) - 0.5) * 30,
      scale: 0.7 + seededRandom(i * 17 + 7) * 0.6,
    })),
  []);

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      const tags = containerRef.current!.querySelectorAll('.chaos-tag');
      gsap.set(tags, { opacity: 0, scale: 0.3, rotation: 0 });
      const tl = gsap.timeline({ delay: 0.2 });
      tl.to(tags, {
        opacity: 1,
        scale: (i) => tagPositions[i]?.scale || 1,
        rotation: (i) => tagPositions[i]?.rot || 0,
        duration: 0.5,
        stagger: { each: 0.04, from: 'random' },
        ease: 'back.out(2)',
      });

      gsap.to('.chaos-tag', {
        y: '+=3',
        duration: 2 + Math.random() * 2,
        ease: 'sine.inOut',
        yoyo: true,
        repeat: -1,
        stagger: { each: 0.15, from: 'random' },
        delay: 2,
      });
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive] });

  const handleClick = () => {
    if (phase === 0) {
      const ctx = gsap.context(() => {
        gsap.to('.chaos-tag', { opacity: 0.06, scale: 0.85, duration: 0.6, stagger: 0.015 });
        gsap.fromTo('.chaos-question', { opacity: 0, scale: 0.85, y: 20 },
          { opacity: 1, scale: 1, y: 0, duration: 0.7, ease: 'back.out(1.5)', delay: 0.4 });
      }, containerRef);
      ctx.revert();
      setPhase(1);
    } else if (phase === 1) {
      const ctx = gsap.context(() => {
        gsap.to('.chaos-question', { opacity: 0, y: -40, duration: 0.5 });
        gsap.to('.chaos-tag', { opacity: 0, scale: 0.3, duration: 0.4, stagger: 0.01 });
        gsap.fromTo('.chaos-answer-title', { opacity: 0, y: 30 },
          { opacity: 1, y: 0, duration: 0.7, ease: 'power3.out', delay: 0.5 });
        gsap.fromTo('.chaos-answer-flow', { opacity: 0, y: 40 },
          { opacity: 1, y: 0, duration: 0.6, ease: 'power3.out', delay: 0.9, stagger: 0.15 });
      }, containerRef);
      ctx.revert();
      setPhase(2);
    } else {
      setPhase(0);
    }
  };

  return (
    <section ref={containerRef}
      className="w-full min-h-[100dvh] flex flex-col items-center justify-center px-6 py-16 relative overflow-hidden cursor-pointer select-none"
      style={{ backgroundColor: 'var(--bg-primary)' }}
      onClick={handleClick}>

      {/* Phase 0: Scattered tags with icons */}
      {phase === 0 && TAGS.map((tag, i) => {
        const pos = tagPositions[i];
        const color = COLORS[i % COLORS.length];
        const Icon = tag.icon;
        return (
          <span key={i}
            className="chaos-tag absolute flex items-center gap-1.5 px-3 py-1.5 rounded-full text-caption font-semibold border whitespace-nowrap"
            style={{
              left: `${45 + pos.x}%`,
              top: `${42 + pos.y}%`,
              borderColor: color,
              color: color,
              backgroundColor: 'var(--bg-secondary)',
            }}>
            <Icon size={14} strokeWidth={2} />
            {tag.text}
          </span>
        );
      })}

      {/* Phase 1: Question */}
      {phase === 1 && (
        <div className="chaos-question relative z-10 text-center max-w-2xl mx-auto opacity-0">
          <HelpCircle className="w-16 h-16 mx-auto mb-5 text-[var(--accent)]" strokeWidth={1.5} />
          <h2 className="text-h1 font-bold text-[var(--text-primary)] mb-3">
            这些概念，是否让您觉得纷繁复杂？
          </h2>
          <p className="text-h3 text-[var(--text-secondary)] mb-6">
            理不清它们之间的关系？
          </p>
          <p className="text-body text-[var(--text-light)] animate-pulse">
            点击继续 →
          </p>
        </div>
      )}

      {/* Phase 2: Answer — 回归系统本身 */}
      {phase === 2 && (
        <div className="relative z-10 text-center max-w-3xl mx-auto">
          <h2 className="chaos-answer-title text-h1 font-bold text-[var(--text-primary)] mb-10 opacity-0">
            让我们回归系统本身
          </h2>
          <div className="flex items-center justify-center gap-4 md:gap-6 mt-6">
            {[
              { label: '输入', sub: '用户要什么', icon: MessageSquare, color: 'var(--primary)' },
              { label: '处理', sub: '系统怎么做', icon: Cpu, color: 'var(--accent)' },
              { label: '输出', sub: '结果是什么', icon: Eye, color: 'var(--success)' },
            ].map((item, i) => (
              <React.Fragment key={i}>
                {i > 0 && (
                  <span className="chaos-answer-flow text-2xl text-[var(--text-light)] opacity-0">→</span>
                )}
                <div className="chaos-answer-flow flex flex-col items-center px-5 py-4 md:px-8 md:py-5 rounded-xl border-2 opacity-0"
                  style={{ borderColor: item.color, backgroundColor: `${item.color}08` }}>
                  <item.icon size={28} style={{ color: item.color }} strokeWidth={1.8} />
                  <span className="text-h2 font-bold mt-2" style={{ color: item.color }}>{item.label}</span>
                  <span className="text-caption text-[var(--text-secondary)] mt-1">{item.sub}</span>
                </div>
              </React.Fragment>
            ))}
          </div>
          <p className="text-body text-[var(--text-light)] mt-10 animate-pulse">
            点击进入下一页 →
          </p>
        </div>
      )}

      {/* Bottom hint */}
      <div className="absolute bottom-8 text-caption text-[var(--text-light)]">
        {phase === 0 ? '点击任意处继续' : phase === 1 ? '点击任意处继续' : '点击重置'}
      </div>
    </section>
  );
};

export default memo(Slide01_Cover);

