              </React.Fragment>
            ))}
            <span className="text-[var(--text-light)]">→</span>
            <span className="px-3 py-1.5 rounded-lg text-body-sm font-semibold" style={{ backgroundColor: '#8B5CF610' }}>🔁 循环</span>
          </div>
